dot("$(0,0,0)$", A, NE);
dot("$(10,0,0)$", B, NW);
dot("$(0,10,0)$", C, NE);
dot("$(0,0,10)$", D,  N);
dot(P);
dot(Q);
dot(R);
dot(T);
[/asy]

